          const section = document.getElementById('backgroundExtraSection');
          const fieldsContainer = document.getElementById('backgroundExtraFields');
          const bg = this.value;

          fieldsContainer.innerHTML = '';

          if (bg === 'Gia đình bình thường' || !bg) {
            section.style.display = 'none';
            return;
          }

          section.style.display = 'block';
          section.style.animation = 'slideUp 0.4s ease-out';

          let html = '';
          if (bg === 'Được đôn lên từ khối dưới') {
            html = `
              <div class="grid-2">
                <div class="input-group">
                  <label>Thành tích hồi cấp 2</label>
                  <div class="select-wrapper">
                    <select id="extra_performance">
