                <div class="input-group">
                  <label>Môn sở trường</label>
                  <div class="select-wrapper">
                    <select id="extra_subject">
                      <option value="Kiến thức lý thuyết">Kiến thức lý thuyết</option>
                      <option value="Thực hành thi đấu">Thực hành thi đấu</option>
                      <option value="Tố chất tổng hợp">Tố chất tổng hợp</option>
                    </select>
                  </div>
                </div>
              </div>
            `;
          } else if (bg === 'Tuyển sinh công khai (Cấp Nhụy)') {
            html = `
              <div class="grid-2">
                <div class="input-group">
                  <label>Bậc xếp hạng ban đầu</label>
                  <div class="select-wrapper">
                    <select id="extra_level">
                      <option value="Cấp Nhụy bậc 1">Cấp Nhụy bậc 1</option>
                      <option value="Cấp Nhụy bậc 2">Cấp Nhụy bậc 2</option>
                      <option value="Cấp Nhụy bậc 3">Cấp Nhụy bậc 3</option>
                    </select>
                  </div>
                </div>
                <div class="input-group">
                  <label>Giải thưởng cao nhất từng đạt</label>
                  <input type="text" id="extra_award" placeholder="Ví dụ: Quán quân giải trẻ U15 Kanto" />
                </div>
