              <div class="input-group" style="margin-top: 15px">
                <label>Danh hiệu / Kinh nghiệm thi đấu</label>
                <textarea id="extra_honors" rows="2" placeholder="Liệt kê các danh hiệu quan trọng hoặc kinh nghiệm thi đấu của bạn..."></textarea>
              </div>
            `;
          } else if (bg === 'Học sinh diện tài trợ') {
            html = `
              <div class="grid-2">
                <div class="input-group">
                  <label>Gia tộc/Doanh nghiệp tài trợ</label>
                  <input type="text" id="extra_sponsor" placeholder="Tên gia tộc hoặc doanh nghiệp" />
