          fieldsContainer.innerHTML = html;
        });

        // Checkbox Limiters
        setupCheckboxLimit('#skillsGroup input[type="checkbox"]', 3);
        setupCheckboxLimit('#sensitiveZonesGroup input[type="checkbox"]', 2);
