      function setupCheckboxLimit(selector, limit) {
        const checkboxes = document.querySelectorAll(selector);
        checkboxes.forEach(cb => {
          cb.addEventListener('change', function () {
            const checked = document.querySelectorAll(`${selector}:checked`);
            if (checked.length > limit) {
              this.checked = false;
              // Optional: Add a subtle shake animation or toast here instead of alert
              // For now, we just prevent checking
            }
          });
        });
      }

      // Submit Logic
      document.getElementById('submitProfile').addEventListener('click', function () {
        // Gather Data
        const name = document.getElementById('studentName').value.trim();
        const birthMonth = document.getElementById('birthMonth').value;
        const birthDay = document.getElementById('birthDay').value;
        const grade = document.getElementById('studentGrade').value;
        const backgroundSelect = document.getElementById('background');
        const background = backgroundSelect.options[backgroundSelect.selectedIndex]?.text || '';

        // Body Data
        const height = document.getElementById('height').value.trim();
        const bodyType = document.getElementById('bodyType').value;
        const breastSize = document.getElementById('breastSize').value;
        const breastShape = document.getElementById('breastShape').value;
        const hipSize = document.getElementById('hipSize').value;
        const vaginaShape = document.getElementById('vaginaShape').value;

        // Partner
        const pastPartnerName = document.getElementById('pastPartnerName').value.trim();
        const pastPartnerDesc = document.getElementById('pastPartnerDesc').value.trim();

        // Extra
        const extraDesc = document.getElementById('extraDesc').value.trim();

        // Background Extra Data
        let backgroundExtraInfo = '';
        const bgValue = document.getElementById('background').value;
        if (bgValue === 'Được đôn lên từ khối dưới') {
          backgroundExtraInfo = ` (Thành tích: ${document.getElementById('extra_performance').value}, Chức vụ: ${document.getElementById('extra_position').value})`;
        } else if (bgValue === 'Thi tuyển đầu vào thống nhất') {
          backgroundExtraInfo = ` (Thứ hạng: ${document.getElementById('extra_rank').value}, Sở trường: ${document.getElementById('extra_subject').value})`;
        } else if (bgValue === 'Tuyển sinh công khai (Cấp Nhụy)') {
          backgroundExtraInfo = ` (Đoạn vị: ${document.getElementById('extra_level').value}, Giải thưởng: ${document.getElementById('extra_award').value || 'Không'})`;
        } else if (bgValue === 'Học sinh chuyển trường đặc biệt') {
          backgroundExtraInfo = ` (Trường cũ: ${document.getElementById('extra_old_school').value || 'Chưa rõ'}, Danh hiệu: ${document.getElementById('extra_honors').value || 'Không'})`;
        } else if (bgValue === 'Học sinh diện tài trợ') {
          backgroundExtraInfo = ` (Nhà tài trợ: ${document.getElementById('extra_sponsor').value || 'Chưa rõ'}, Địa vị: ${document.getElementById('extra_status').value})`;
        } else if (bgValue === 'Du học sinh trao đổi') {
          backgroundExtraInfo = ` (Quốc tịch: ${document.getElementById('extra_country').value || 'Chưa rõ'}, Thời hạn: ${document.getElementById('extra_duration').value})`;
        }

        // Checkboxes
        const sensitiveZones =
          Array.from(document.querySelectorAll('#sensitiveZonesGroup input:checked'))
            .map(cb => cb.value)
            .join('、') || 'Chưa khai phá';
        const skills =
          Array.from(document.querySelectorAll('#skillsGroup input:checked'))
            .map(cb => cb.value)
            .join('、') || 'Vẫn là tờ giấy trắng';

        // Validation
        if (!name || !birthMonth || !birthDay || !grade || !document.getElementById('background').value) {
          // Simple shake animation for form
          const form = document.getElementById('academyForm');
          form.style.transform = 'translateX(10px)';
          setTimeout(() => (form.style.transform = 'translateX(-10px)'), 100);
          setTimeout(() => (form.style.transform = 'translateX(0)'), 200);
          return;
        }

        const finalName = name;
        const birthday = `Ngày ${birthDay} Tháng ${birthMonth}`;

        let bodyTraits = [];
        if (height) bodyTraits.push(`Chiều cao: ${height}`);
        if (bodyType) bodyTraits.push(`Dáng người: ${bodyType}`);
        if (breastSize) bodyTraits.push(`Cúp ngực: ${breastSize}`);
        if (breastShape) bodyTraits.push(`Dáng ngực: ${breastShape}`);
        if (hipSize) bodyTraits.push(`Dáng mông: ${hipSize}`);
        if (vaginaShape) bodyTraits.push(`Dáng huyệt: ${vaginaShape}`);
        const bodyTraitsText = bodyTraits.length > 0 ? bodyTraits.join('; ') : 'Tiêu chuẩn';

        let partnerInfo = '';
        if (grade === 'Khối cấp 3' && pastPartnerName) {
          partnerInfo = `\nCộng sự cấp 2：${pastPartnerName} (${pastPartnerDesc || 'Một câu chuyện đã bị lãng quên'})`;
        }

        // Construct Output
        const profileDetails = `
【Thông tin khởi đầu】
Thời gian: Ngày khai giảng 3/4 - Thứ Ba - 9:00
Địa điểm: Nơi báo danh tân sinh viên Học viện
Họ tên: ${finalName}
Sinh nhật: ${birthday}
Bộ: ${grade}
Xuất thân: ${background}${backgroundExtraInfo}
Đặc điểm cơ thể: ${bodyTraitsText}
Điểm nhạy cảm đặc biệt: ${sensitiveZones}${partnerInfo}
Kỹ thuật sở trường: ${skills}
Thiết lập bổ sung: ${extraDesc || 'Không'}

【Lệnh thực thi】
1. **Khởi tạo biến nhân vật chính**:
   - Dựa trên 【Thông tin khởi đầu】 cập nhật các biến liên quan đến \`Nhân vật chính\` (Họ tên, sinh nhật, xuất thân, dữ liệu cơ thể...).
   - Dựa trên xuất thân và thiết lập, ban cho một 【Danh hiệu】 khởi đầu.
   - Dựa trên kỹ thuật sở trường, khởi tạo \`Nhân vật chính.Kỹ năng\`.
   - Nếu có cộng sự cấp 2, cập nhật \`Nhân vật chính.Quan hệ xã hội\` và các biến liên quan.
   - Tiền khởi điểm mặc định là 10000, nếu xuất thân là "Học sinh diện tài trợ" thì tăng thêm lượng thích hợp.
   - Thuộc tính khởi đầu (Thể lực, Kỹ thuật...) được thiết lập hợp lý dựa trên xuất thân và đặc điểm cơ thể.

2. **Tạo cốt truyện mở đầu**:
   - Thời gian: Ngày khai giảng 3/4 Thứ Ba 9:00
   - Địa điểm: Nơi báo danh tân sinh viên Học viện Lê Hoa Giang
   - Nội dung: Miêu tả cảnh nhân vật chính nhập học báo danh. Hãy kết hợp miêu tả 【Đặc điểm cơ thể】 (như ấn tượng thị giác từ chiều cao, vóc dáng), 【Xuất thân】 (hoạt động tâm lý hoặc phản ứng của người xung quanh) và 【Thiết lập bổ sung】.
   - Kết thúc: Dẫn dắt nhân vật chính hoàn thành thủ tục báo danh, chuẩn bị đón chào cuộc sống học đường mới.
`;

        // Trigger Slash
        if (typeof triggerSlash === 'function') {
          triggerSlash(`/send ${profileDetails.trim()}|/trigger`);
        } else {
          console.log(profileDetails.trim());
        }

        // Show Result
        const resultContent = document.getElementById('resultContent');
        resultContent.innerHTML = `
                <p><strong>Họ tên：</strong>${finalName}</p>
                <p><strong>Sinh nhật：</strong>${birthday}</p>
                <p><strong>Bộ：</strong>${grade}</p>
                <p><strong>Xuất thân：</strong>${background}${backgroundExtraInfo}</p>
                <p><strong>Dữ liệu cơ thể：</strong>${bodyTraitsText}</p>
                <p><strong>Điểm nhạy cảm：</strong>${sensitiveZones}</p>
                ${partnerInfo ? `<p><strong>Cộng sự cấp 2：</strong>${pastPartnerName}</p>` : ''}
                <p><strong>Kỹ thuật sở trường：</strong>${skills}</p>
                ${extraDesc ? `<p><strong>Thiết lập bổ sung：</strong>${extraDesc}</p>` : ''}
            `;

        // Transition
        const form = document.getElementById('academyForm');
        const result = document.getElementById('resultDisplay');

        form.style.opacity = '0';
        form.style.transform = 'translateY(-20px)';

        setTimeout(() => {
          form.style.display = 'none';
          result.style.display = 'block';
          result.style.opacity = '0';
          result.style.transform = 'translateY(20px)';

          // Trigger reflow
          void result.offsetWidth;

          result.style.transition = 'all 0.5s ease';
          result.style.opacity = '1';
          result.style.transform = 'translateY(0)';
        }, 300);
      });

      // Edit Logic
      document.getElementById('editBtn').addEventListener('click', function () {
        const form = document.getElementById('academyForm');
        const result = document.getElementById('resultDisplay');

        result.style.opacity = '0';
        result.style.transform = 'translateY(20px)';

        setTimeout(() => {
          result.style.display = 'none';
          form.style.display = 'block';
          // Trigger reflow
          void form.offsetWidth;

          form.style.opacity = '1';
          form.style.transform = 'translateY(0)';
        }, 300);
      });
    </script>
  </body>
</html>
